// src/api/auth.js

const API_BASE = "http://localhost:8080/api";

async function request(path, options = {}) {
  const raw = localStorage.getItem("zenelait-auth");
  let token = null;

  if (raw) {
    try {
      const parsed = JSON.parse(raw);
      token = parsed.accessToken; // ✅ correct source
    } catch {}
  }

  console.log("TOKEN SENT:", token); // 🔍 DEBUG

  const res = await fetch(`http://localhost:8080/api${path}`, {
    headers: {
      "Content-Type": "application/json",
      Authorization: token ? `Bearer ${token}` : "",
      ...(options.headers || {}),
    },
    ...options,
  });

  const body = await res.json().catch(() => ({}));

  if (!res.ok || body.success === false) {
    throw new Error(body.message || "Request failed");
  }

  return body.data || body;
}

export async function login(email, password, role) {
  const data= request(`/auth/${role}/login`, {
    method: "POST",
    body: JSON.stringify({ email, password }),
  });
    if (data.accessToken) {
    localStorage.setItem("token", data.accessToken);
  }

  return data;
}

export async function getAllStudents() {
  return request("/admin/students");
}

export async function getAllTeachers(){
  return request("/admin/teachers");
}

export async function getAllParents(){
  return request("/admin/parents");
}


export async function registerUser(payload) {
  const role = payload.role.toLowerCase(); // "ADMIN" → "admin"
  return request(`/auth/${role}/register`, {
    method: "POST",
    body: JSON.stringify(payload),
  });
}
